#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int ans = N/4 + (N%4 != 0);
        printf("%d\n", ans);
    }
    return 0;
}

